onClick:
{{(() => {
  if (dp_rel_inicio.selectedDate && dp_rel_fim.selectedDate && moment(dp_rel_inicio.selectedDate).isAfter(moment(dp_rel_fim.selectedDate), 'day')) {
    showAlert('Período inválido: Data início não pode ser maior que Data fim.', 'error');
    return;
  }

  const perfil = get_meu_perfil_relatorios.data?.[0]?.perfil || 'atendente';
  const escopo = sel_rel_escopo.selectedOptionValue || 'meus_tickets';
  if (escopo === 'completo' && !['admin', 'supervisor'].includes(perfil)) {
    showAlert('Você não tem permissão para relatório completo. Use Meus tickets.', 'warning');
    return;
  }

  relatorio_tickets.run()
    .then(() => showAlert(`Relatório gerado com ${relatorio_tickets.data?.length || 0} registro(s).`, 'success'))
    .catch(() => showAlert('Não foi possível gerar o relatório. Revise os filtros e tente novamente.', 'error'));
})();}}
